import{_ as a,o as r,c as l,ae as o}from"./chunks/framework.Czhw_PXq.js";const q=JSON.parse('{"title":"《让时间陪你慢慢变富》第3讲：普通人做投资的唯一正确方式","description":"为什么定投是唯一靠谱的投资方式？微笑曲线与猥琐曲线的奥秘","frontmatter":{"title":"《让时间陪你慢慢变富》第3讲：普通人做投资的唯一正确方式","description":"为什么定投是唯一靠谱的投资方式？微笑曲线与猥琐曲线的奥秘","pubDate":"2026-05-16"},"headers":[],"relativePath":"posts/lixiaolai-dt-03.md","filePath":"posts/lixiaolai-dt-03.md"}'),i={name:"posts/lixiaolai-dt-03.md"};function d(e,t,n,h,s,u){return r(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="第3讲-普通人做投资的唯一正确方式" tabindex="-1">第3讲：普通人做投资的唯一正确方式 <a class="header-anchor" href="#第3讲-普通人做投资的唯一正确方式" aria-label="Permalink to &quot;第3讲：普通人做投资的唯一正确方式&quot;">​</a></h1><blockquote><p>在交易市场这个神奇的地方，普通人唯一靠谱的投资方式只有定投——切记！</p></blockquote><h2 id="引言-先直接说结论" tabindex="-1">引言：先直接说结论 <a class="header-anchor" href="#引言-先直接说结论" aria-label="Permalink to &quot;引言：先直接说结论&quot;">​</a></h2><p>在交易市场这个神奇的地方，普通人唯一靠谱的投资方式只有<strong>定投</strong>——切记！</p><p>这一讲将通过真实的数据对比，让你看到定投策略的神奇之处。</p><h2 id="第一部分-定投数据演示" tabindex="-1">第一部分：定投数据演示 <a class="header-anchor" href="#第一部分-定投数据演示" aria-label="Permalink to &quot;第一部分：定投数据演示&quot;">​</a></h2><h3 id="案例背景" tabindex="-1">案例背景 <a class="header-anchor" href="#案例背景" aria-label="Permalink to &quot;案例背景&quot;">​</a></h3><p>以下是龙门基金2018年9月至2019年7月的走势数据：</p><p>假设你从2018年9月开始，<strong>每月定投龙门基金1000美元</strong>，一直定投了11个月。</p><h3 id="定投数据表" tabindex="-1">定投数据表 <a class="header-anchor" href="#定投数据表" aria-label="Permalink to &quot;定投数据表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时间</th><th>价格</th><th>累计定投</th><th>每次购买份数</th><th>市值累计</th></tr></thead><tbody><tr><td>2018.9</td><td>$74.00</td><td>$1,000</td><td>13.51</td><td>$1,000</td></tr><tr><td>2018.10</td><td>$64.00</td><td>$2,000</td><td>15.63</td><td>$1,865</td></tr><tr><td>2018.11</td><td>$62.00</td><td>$3,000</td><td>16.13</td><td>$2,807</td></tr><tr><td>2018.12</td><td>$34.00</td><td>$4,000</td><td>29.41</td><td>$2,539</td></tr><tr><td>2019.1</td><td>$31.00</td><td>$5,000</td><td>32.26</td><td>$3,315</td></tr><tr><td>2019.2</td><td>$29.00</td><td>$6,000</td><td>34.48</td><td>$4,101</td></tr><tr><td>2019.3</td><td>$38.00</td><td>$7,000</td><td>26.32</td><td>$6,374</td></tr><tr><td>2019.4</td><td>$45.00</td><td>$8,000</td><td>22.22</td><td>$8,548</td></tr><tr><td>2019.5</td><td>$52.00</td><td>$9,000</td><td>19.23</td><td>$10,878</td></tr><tr><td>2019.6</td><td>$83.00</td><td>$10,000</td><td>12.05</td><td>$18,363</td></tr><tr><td>2019.7</td><td>$82.00</td><td>$11,000</td><td>12.20</td><td>$19,141</td></tr></tbody></table><p><strong>关键数据：</strong></p><ul><li>错过了最低点（2018.12.15）：$23.00</li><li>错过了最高点（2019.6.25）：$92.00</li><li><strong>平均成本：$54.00</strong></li><li>当前价格：$82.00</li></ul><h3 id="收益率对比" tabindex="-1">收益率对比 <a class="header-anchor" href="#收益率对比" aria-label="Permalink to &quot;收益率对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>投资方式</th><th>收益率</th></tr></thead><tbody><tr><td><strong>定投策略</strong></td><td><strong>74.01%</strong></td></tr><tr><td>一把梭（2018年9月全进）</td><td>10.81%</td></tr></tbody></table><p><strong>结果：</strong></p><ul><li>累计投资：$11,000</li><li>当前市值：$19,141</li><li>定投收益率：<strong>74.01%</strong></li></ul><h2 id="第二部分-微笑曲线-vs-猥琐曲线" tabindex="-1">第二部分：微笑曲线 vs 猥琐曲线 <a class="header-anchor" href="#第二部分-微笑曲线-vs-猥琐曲线" aria-label="Permalink to &quot;第二部分：微笑曲线 vs 猥琐曲线&quot;">​</a></h2><h3 id="微笑曲线" tabindex="-1">微笑曲线 <a class="header-anchor" href="#微笑曲线" aria-label="Permalink to &quot;微笑曲线&quot;">​</a></h3><p>在以上龙门基金的11个月的数据之中，价格曲线画出了一个迷人的**&quot;微笑曲线&quot;**。</p><p>对于定投者来说：</p><ul><li>你会错过最高点（$92）</li><li>你也会错过最低点（$23）</li><li>但你的均价为$54</li><li>而当前价格为$85</li></ul><p><strong>定投者的心态：</strong></p><ul><li>价格下跌 → 兴奋（可以买到更便宜的筹码）</li><li>价格上升 → 开心（之前的投资开始盈利）</li><li>整个过程 → 幸福</li></ul><h3 id="猥琐曲线" tabindex="-1">猥琐曲线 <a class="header-anchor" href="#猥琐曲线" aria-label="Permalink to &quot;猥琐曲线&quot;">​</a></h3><p>市场上采取定投策略的人永远是少数，而上面这个所谓的&quot;微笑曲线&quot;，对并未采取定投策略的人来说，很可能是截然相反的**&quot;猥琐曲线&quot;**。</p><p>那绝对不是一张善意的笑脸，而是一张你在《蝙蝠侠》故事里见到过的那个小丑的邪恶的笑脸——他的嘴里还在阴森地嘟囔着：&quot;WHY SO SERIOUS?&quot;</p><h3 id="一把梭的悲惨经历" tabindex="-1">一把梭的悲惨经历 <a class="header-anchor" href="#一把梭的悲惨经历" aria-label="Permalink to &quot;一把梭的悲惨经历&quot;">​</a></h3><p>假设你的投资方式是绝大多数人爱干的那种，所谓的&quot;一把梭&quot;……</p><p>你在2018年的9月份一把梭进去$11,000，然后拿到11个月后：</p><ul><li>倒也没有赔，有大约**10.81%**的收益</li><li>虽然比**74.01%**差远了，可毕竟没有赔啊！</li></ul><p><strong>然而，你能一路拿到11个月之后的可能性其实并不大。</strong></p><h3 id="为什么坚持不下去" tabindex="-1">为什么坚持不下去 <a class="header-anchor" href="#为什么坚持不下去" aria-label="Permalink to &quot;为什么坚持不下去&quot;">​</a></h3><p>对&quot;一把梭&quot;的人来说，这个曲线绝对是猥琐曲线。</p><p>别说接下来的每个月了，接下来的每一天、每时每刻，你都会痛苦万分焦虑不已。在接下来的整整半年之内，你唯一的感受就是你的资产在每分每秒地缩水。</p><p><strong>痛苦和快乐并不是对称的</strong>，我们的基因决定了我们的感受。赔掉10块钱的痛苦远远大于赚到10块钱的快乐。</p><p>你的感觉绝对就好像是正在被那个邪恶的小丑蹂躏，并且看着他吐吐舌头，听着他阴森地嘟囔：&quot;干吗那么当回事儿啊……&quot;</p><h3 id="割肉的悲剧" tabindex="-1">割肉的悲剧 <a class="header-anchor" href="#割肉的悲剧" aria-label="Permalink to &quot;割肉的悲剧&quot;">​</a></h3><p>&quot;一把梭&quot;的人忍受不了太久的痛苦——事实上，任何人都无法长期承受痛苦。这跟所谓的&quot;坚强&quot;完全没有任何关系。</p><p>在一个月，或者两个月、三个月的痛苦之后，甚至在事后看来马上就要挺过去了的时候，即，在第六个月的时候（或者稍前），很多人会基于种种原因离场——交易市场上把这种行为称为**&quot;割肉&quot;**。</p><p>你看，韭菜都是自己割自己的，并且割下来的都是血淋淋的肉。</p><h2 id="第三部分-定投者的心态" tabindex="-1">第三部分：定投者的心态 <a class="header-anchor" href="#第三部分-定投者的心态" aria-label="Permalink to &quot;第三部分：定投者的心态&quot;">​</a></h2><h3 id="截然相反的世界" tabindex="-1">截然相反的世界 <a class="header-anchor" href="#截然相反的世界" aria-label="Permalink to &quot;截然相反的世界&quot;">​</a></h3><p>如果你是采用定投方式的投资人，那么你所身处的完全是另外一个世界——虽然它们看起来一模一样，虽然除了你之外绝大多数人根本无法体会你的感受，因为所有的感受都是截然相反的。</p><p><strong>定投是使用自己的长期去支持的行为。</strong></p><p>所以，既然赌上了自己的未来，那么，在选择的时候就经过了深思熟虑。于是，如果第一次买入之后产生了价格下跌，那么，对你来说之后的每一次下跌都是<strong>降低均价的时机</strong>。</p><p>&quot;一把梭&quot;的人在那里体验着寒冬，瑟瑟发抖，你却截然相反，你神清气爽，你为你又增加了更多的低价筹码而倍感幸福。</p><h3 id="向前平移入场时间" tabindex="-1">向前平移入场时间 <a class="header-anchor" href="#向前平移入场时间" aria-label="Permalink to &quot;向前平移入场时间&quot;">​</a></h3><p>如果在这个过程中，你看着低价筹码却被人拦着不让你买，你会跟他拼的。你说是不是？</p><p>你冷吗？你瑟瑟发抖吗？你感受不到啊！你兴奋着呢，每次定投都很兴奋，因为每次均价降低都相当于是**&quot;向前平移了你的入场时间&quot;**——你才不会像很多半吊子那样天天懊恼，&quot;唉！我要是早知道就好了！&quot;或者&quot;我怎么才知道呢？&quot;</p><p>他们总而言之就是觉得自己来晚了。你不一样，你知道你的行为正在把自己的相对入场时间不断提前。</p><h3 id="价格回升时的差异" tabindex="-1">价格回升时的差异 <a class="header-anchor" href="#价格回升时的差异" aria-label="Permalink to &quot;价格回升时的差异&quot;">​</a></h3><p>六个月后，价格开始缓慢爬升了，你以为当初割肉离场的人会这个时候冲进来&quot;一把梭&quot;吗？</p><p><strong>不会的。</strong></p><p>他们怕死了——之前生不如死的经历会让他们对恐惧的预期更为强烈。于是，几乎百分之百发生的事情是，他们在犹豫之中，手中没有任何筹码地眼睁睁看着价格上涨……</p><p>跌的时候他们正是因为怕死了才跑的，现在涨的时候他们更害怕——直到他们的情绪崩溃，可能价格已经很高了，就要开始下一个&quot;猥琐曲线&quot;的时候，他们竟然又入场了……</p><h2 id="第四部分-同样的世界-不同的命运" tabindex="-1">第四部分：同样的世界，不同的命运 <a class="header-anchor" href="#第四部分-同样的世界-不同的命运" aria-label="Permalink to &quot;第四部分：同样的世界，不同的命运&quot;">​</a></h2><h3 id="轮回的可怕" tabindex="-1">轮回的可怕 <a class="header-anchor" href="#轮回的可怕" aria-label="Permalink to &quot;轮回的可怕&quot;">​</a></h3><p>对他们来说，轮回是非常可怕的，因为无论他们如何做，他们感受到的都是恶意满满的世界。</p><p>有了之前的讲解，现在解释起来就很简单，因为对他们来说，任何投资标的的价格曲线，都是由无数个**&quot;猥琐曲线&quot;**构成的。</p><p>你说这样的命运有多么可怕？</p><h3 id="中国股市的误解" tabindex="-1">中国股市的误解 <a class="header-anchor" href="#中国股市的误解" aria-label="Permalink to &quot;中国股市的误解&quot;">​</a></h3><p>你肯定听说过，中国股市在过去的十年里增长等于零！这个事实使很多人得出一个结论：投资股市是不划算的！</p><p>然而，事实真的如此吗？</p><p><strong>显然不是。</strong></p><p>即便是最终增长等于零，过去的十年里画出了一个大大的曲线，对定投者来说，那是**&quot;微笑曲线&quot;**啊！</p><p>当然，对绝大多数人来说，收益不仅仅是零，更可能是负数，因为他们实际经历的是**&quot;猥琐曲线&quot;**。</p><h3 id="镜像世界" tabindex="-1">镜像世界 <a class="header-anchor" href="#镜像世界" aria-label="Permalink to &quot;镜像世界&quot;">​</a></h3><p>你看，明明是同样的世界，人们的感受却截然相反，这是不是很神奇？</p><p>如果你是采取定投策略的人，那么，一瞬间，同样的世界对你来说是另外一个样子，因为你所面对的价格曲线是由无数个**&quot;微笑曲线&quot;**构成的！</p><p>这世界，幸福本来就是罕见稀缺的。我就问你，这种不可向人诉说的幸福是不是更稀缺更宝贵呢？</p><h2 id="第五部分-实战应用" tabindex="-1">第五部分：实战应用 <a class="header-anchor" href="#第五部分-实战应用" aria-label="Permalink to &quot;第五部分：实战应用&quot;">​</a></h2><h3 id="定投策略要点" tabindex="-1">定投策略要点 <a class="header-anchor" href="#定投策略要点" aria-label="Permalink to &quot;定投策略要点&quot;">​</a></h3><ol><li><p><strong>确定长期</strong></p><ul><li>至少跨越一个牛熊周期（通常7-10年）</li><li>用闲钱投资，不影响生活</li></ul></li><li><p><strong>设定定期</strong></p><ul><li>每月、每周固定时间</li><li>自动化执行，避免情绪干扰</li></ul></li><li><p><strong>确定定额</strong></p><ul><li>固定金额，不因市场波动改变</li><li>量力而行，可持续最重要</li></ul></li><li><p><strong>选择标的</strong></p><ul><li>选择市场最看好的标的</li><li>流动性好，长期看涨</li></ul></li></ol><h3 id="心态建设" tabindex="-1">心态建设 <a class="header-anchor" href="#心态建设" aria-label="Permalink to &quot;心态建设&quot;">​</a></h3><table tabindex="0"><thead><tr><th>市场情况</th><th>一把梭者</th><th>定投者</th></tr></thead><tbody><tr><td>价格下跌</td><td>恐慌、割肉</td><td>兴奋、加仓</td></tr><tr><td>价格横盘</td><td>焦虑、怀疑</td><td>淡定、坚持</td></tr><tr><td>价格上涨</td><td>后悔、追高</td><td>开心、盈利</td></tr></tbody></table><h2 id="第六部分-常见陷阱与误区" tabindex="-1">第六部分：常见陷阱与误区 <a class="header-anchor" href="#第六部分-常见陷阱与误区" aria-label="Permalink to &quot;第六部分：常见陷阱与误区&quot;">​</a></h2><h3 id="陷阱一-试图择时" tabindex="-1">陷阱一：试图择时 <a class="header-anchor" href="#陷阱一-试图择时" aria-label="Permalink to &quot;陷阱一：试图择时&quot;">​</a></h3><p><strong>表现</strong>：想买到最低点，卖到最高点</p><p><strong>真相</strong>：</p><ul><li>最低点只有一个，很难抓住</li><li>定投不需要择时，分散了择时风险</li><li>长期看，均价才是决定收益的关键</li></ul><h3 id="陷阱二-中途放弃" tabindex="-1">陷阱二：中途放弃 <a class="header-anchor" href="#陷阱二-中途放弃" aria-label="Permalink to &quot;陷阱二：中途放弃&quot;">​</a></h3><p><strong>表现</strong>：市场下跌时停止定投</p><p><strong>真相</strong>：</p><ul><li>下跌时停止，错过了降低均价的机会</li><li>定投的优势就在于在低位积累更多筹码</li><li>坚持才能看到微笑曲线</li></ul><h3 id="陷阱三-随意改变金额" tabindex="-1">陷阱三：随意改变金额 <a class="header-anchor" href="#陷阱三-随意改变金额" aria-label="Permalink to &quot;陷阱三：随意改变金额&quot;">​</a></h3><p><strong>表现</strong>：市场好时多投，差时少投</p><p><strong>真相</strong>：</p><ul><li>这违背了定投的基本原则</li><li>容易在高位买入过多</li><li>定额才能发挥定投的优势</li></ul><h3 id="陷阱四-频繁查看账户" tabindex="-1">陷阱四：频繁查看账户 <a class="header-anchor" href="#陷阱四-频繁查看账户" aria-label="Permalink to &quot;陷阱四：频繁查看账户&quot;">​</a></h3><p><strong>表现</strong>：每天看账户，被短期波动影响</p><p><strong>真相</strong>：</p><ul><li>定投是长期策略，短期波动不重要</li><li>频繁查看容易产生焦虑</li><li>设置好自动定投后，少看账户</li></ul><h2 id="本章总结" tabindex="-1">本章总结 <a class="header-anchor" href="#本章总结" aria-label="Permalink to &quot;本章总结&quot;">​</a></h2><h3 id="核心要点回顾" tabindex="-1">核心要点回顾 <a class="header-anchor" href="#核心要点回顾" aria-label="Permalink to &quot;核心要点回顾&quot;">​</a></h3><ol><li><strong>定投是唯一靠谱的方式</strong>：对普通人来说</li><li><strong>微笑曲线 vs 猥琐曲线</strong>：同样的市场，不同的命运</li><li><strong>定投收益率74.01% vs 一把梭10.81%</strong>：数据说话</li><li><strong>心态决定结果</strong>：定投者在下跌时兴奋</li><li><strong>长期持有是关键</strong>：跨越牛熊周期</li></ol><h3 id="关键概念" tabindex="-1">关键概念 <a class="header-anchor" href="#关键概念" aria-label="Permalink to &quot;关键概念&quot;">​</a></h3><ul><li><strong>微笑曲线</strong>：定投者经历的价格曲线，先跌后涨</li><li><strong>猥琐曲线</strong>：一把梭者经历的价格曲线，充满痛苦</li><li><strong>割肉</strong>：在低位卖出，造成实际亏损</li><li><strong>向前平移入场时间</strong>：均价降低的效果</li></ul><h3 id="行动建议" tabindex="-1">行动建议 <a class="header-anchor" href="#行动建议" aria-label="Permalink to &quot;行动建议&quot;">​</a></h3><ol><li><strong>选择标的</strong>：市场最看好的股票或指数基金</li><li><strong>设定计划</strong>：每月固定金额、固定时间</li><li><strong>自动执行</strong>：避免情绪干扰</li><li><strong>长期持有</strong>：至少7-10年</li><li><strong>少看账户</strong>：避免被短期波动影响</li></ol><h3 id="下章预告" tabindex="-1">下章预告 <a class="header-anchor" href="#下章预告" aria-label="Permalink to &quot;下章预告&quot;">​</a></h3><p>下一讲《定投策略神奇力量背后的深刻机理》，我们将深入理解定投策略背后的原理：主动人格、边界意识、趋势的力量，以及为什么定投是&quot;主动地被动&quot;的最佳践行策略。</p><hr><p><em>本文基于李笑来《让时间陪你慢慢变富》第4章整理。</em></p>',104)])])}const b=a(i,[["render",d]]);export{q as __pageData,b as default};
